/**
 * Structured Logger using Pino
 * Follows U-BRAIN backend-patterns logging standards
 */

interface LogContext {
  userId?: string
  requestId?: string
  method?: string
  path?: string
  [key: string]: unknown
}

class Logger {
  private isDevelopment = process.env.NODE_ENV === 'development'

  log(level: 'info' | 'warn' | 'error', message: string, context?: LogContext) {
    const entry = {
      timestamp: new Date().toISOString(),
      level,
      message,
      ...context
    }

    if (this.isDevelopment) {
      // Pretty print in development
      const emoji = level === 'error' ? '❌' : level === 'warn' ? '⚠️' : 'ℹ️'
      console.log(`${emoji} [${level.toUpperCase()}] ${message}`, context || '')
    } else {
      // JSON format in production
      console.log(JSON.stringify(entry))
    }
  }

  info(message: string, context?: LogContext) {
    this.log('info', message, context)
  }

  warn(message: string, context?: LogContext) {
    this.log('warn', message, context)
  }

  error(message: string, error: Error | unknown, context?: LogContext) {
    const errorDetails = error instanceof Error ? {
      error: error.message,
      stack: error.stack
    } : { error: String(error) }

    this.log('error', message, {
      ...context,
      ...errorDetails
    })
  }
}

export const logger = new Logger()
export default logger

'use client'

import React, { Component, ErrorInfo, ReactNode } from 'react'
import { logger } from '@/lib/utils/logger'
import { GlassCard } from './GlassCard'
import { NeonButton } from './NeonButton'

interface ErrorBoundaryProps {
  children: ReactNode
  fallback?: ReactNode
}

interface ErrorBoundaryState {
  hasError: boolean
  error: Error | null
  errorInfo: ErrorInfo | null
}

/**
 * Error Boundary Component
 * Follows U-BRAIN frontend-patterns error handling standards
 */
export class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props)
    this.state = {
      hasError: false,
      error: null,
      errorInfo: null
    }
  }

  static getDerivedStateFromError(error: Error): Partial<ErrorBoundaryState> {
    return { hasError: true, error }
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    // Log error with structured logging
    logger.error('Error boundary caught error', error, {
      componentStack: errorInfo.componentStack,
      errorBoundary: true
    })

    this.setState({
      error,
      errorInfo
    })
  }

  handleReset = () => {
    this.setState({
      hasError: false,
      error: null,
      errorInfo: null
    })
  }

  render() {
    if (this.state.hasError) {
      // Custom fallback UI
      if (this.props.fallback) {
        return this.props.fallback
      }

      // Default error UI with cyberpunk theme
      return (
        <div className="min-h-screen bg-gradient-to-br from-dark-navy-dark via-dark-navy to-dark-navy-light flex items-center justify-center p-8">
          <GlassCard variant="neon-pink" blur="heavy" className="max-w-2xl w-full p-8">
            <div className="text-center">
              {/* Error Icon */}
              <div className="mb-6">
                <svg
                  className="w-20 h-20 mx-auto text-neon-pink"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"
                  />
                </svg>
              </div>

              {/* Error Title */}
              <h1 className="text-4xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-neon-pink via-neon-purple to-neon-blue mb-4">
                Something Went Wrong
              </h1>

              {/* Error Message */}
              <p className="text-gray-300 mb-6">
                We encountered an unexpected error. Don't worry, we've logged the issue and will fix it soon.
              </p>

              {/* Error Details (Development Only) */}
              {process.env.NODE_ENV === 'development' && this.state.error && (
                <div className="mb-6 text-left">
                  <details className="glass-medium p-4 rounded-lg">
                    <summary className="cursor-pointer text-neon-purple font-semibold mb-2">
                      Error Details (Dev Mode)
                    </summary>
                    <div className="text-sm text-gray-400 font-mono">
                      <p className="text-red-400 mb-2">{this.state.error.message}</p>
                      {this.state.error.stack && (
                        <pre className="overflow-auto max-h-40 text-xs">
                          {this.state.error.stack}
                        </pre>
                      )}
                    </div>
                  </details>
                </div>
              )}

              {/* Action Buttons */}
              <div className="flex gap-4 justify-center">
                <NeonButton
                  variant="primary"
                  glowColor="pink"
                  onClick={this.handleReset}
                >
                  Try Again
                </NeonButton>
                <NeonButton
                  variant="secondary"
                  glowColor="blue"
                  onClick={() => window.location.href = '/'}
                >
                  Go Home
                </NeonButton>
              </div>
            </div>
          </GlassCard>
        </div>
      )
    }

    return this.props.children
  }
}

export default ErrorBoundary

